export enum Timeframe {
  M15 = '15m',
  H1 = '1h',
  H4 = '4h',
  D1 = '1d'
}

export enum MarketTrend {
  BULLISH = 'Bullish',
  BEARISH = 'Bearish',
  SIDEWAYS = 'Sideways'
}

export enum BTCBias {
  STRONGLY_BULLISH = 'Strongly Bullish',
  NEUTRAL = 'Neutral',
  STRONGLY_BEARISH = 'Strongly Bearish'
}

export interface TradeAnalysis {
  symbol: string;
  marketType: 'Spot' | 'Futures';
  timeframe: Timeframe;
  marketBias: string;
  btcTrendImpact: string;
  altcoinStrength: string;
  trend: string;
  structure: string;
  keySupport: string;
  keyResistance: string;
