  target1: string;
  target2: string;
  riskRewardRatio: string;
  confidenceLevel: 'Low' | 'Medium' | 'High';
  reasoning: string[];
  groundingSources?: { web: { uri: string; title: string } }[];
  rawOutput?: string;
}

export interface AnalysisInput {
  symbol: string;
  timeframe: Timeframe;
  marketTrend: MarketTrend;
  btcBias: BTCBias;
  rsi: string;
  macd: string;
  ema: string;
  priceAction: string;
  volume: string;
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { AnalysisInput } from "../types";

export const analyzeTrade = async (input: AnalysisInput) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this specific setup:
    - Symbol: ${input.symbol}/USDT
    - Timeframe: ${input.timeframe}
    - User Observed Market Trend: ${input.marketTrend}
    - BTC Market Bias: ${input.btcBias}
    - Last 1-2 days Price Action: ${input.priceAction}
    - Indicators: RSI: ${input.rsi}, MACD: ${input.macd}, EMA: ${input.ema}
    - Volume & Breakout Data: ${input.volume}

    Use Google Search to cross-reference current market sentiment and the latest 24h price action for ${input.symbol}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    const text = response.text || "Analysis failed.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      sources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

