import React from 'react';

interface AnalysisResultProps {
  content: string;
  sources?: any[];
}

const AnalysisResult: React.FC<AnalysisResultProps> = ({ content, sources }) => {
  if (!content) return null;

  const isBuy = content.includes('Action: BUY');
  const isSell = content.includes('Action: SELL');
  const isNoTrade = content.includes('Action: NO TRADE');

  return (
    <div className="bg-[#1e2329] border border-[#2b3139] rounded-xl overflow-hidden shadow-2xl">
      <div className={`p-1 ${isBuy ? 'bg-green-500' : isSell ? 'bg-red-500' : 'bg-yellow-500'}`} />
      <div className="p-6 md:p-8">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold tracking-tight text-white flex items-center gap-2">
            <i className="fa-solid fa-chart-line text-[#f0b90b]"></i>
            ANALYSIS REPORT
          </h2>
          <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${
            isBuy ? 'bg-green-500/20 text-green-400 border border-green-500/40' : 
            isSell ? 'bg-red-500/20 text-red-400 border border-red-500/40' : 
            'bg-gray-500/20 text-gray-400 border border-gray-500/40'
          }`}>
            {isBuy ? 'Bullish Setup' : isSell ? 'Bearish Setup' : 'Neutral Context'}
          </div>
        </div>

        <pre className="mono text-sm leading-relaxed whitespace-pre-wrap text-gray-300 bg-[#0b0e11] p-4 rounded-lg border border-[#2b3139] overflow-x-auto">
          {content}
        </pre>

        {sources && sources.length > 0 && (
          <div className="mt-6 pt-6 border-t border-[#2b3139]">
            <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Grounding Sources</h3>
            <div className="flex flex-wrap gap-2">
              {sources.map((source, i) => (
                source.web && (
                  <a 
