                    rel="noopener noreferrer"
                    className="text-xs bg-[#2b3139] hover:bg-[#474d57] text-[#f0b90b] px-3 py-1.5 rounded flex items-center gap-2 transition-colors border border-transparent hover:border-[#f0b90b]/30"
