      btn: "Compute Trade Signal",
      loading: "Processing Matrix...",
      desc: "Fully automatic scan: Momentum + Trend + BTC bias."
    },
    hi: {
      select: "टोकन चुनें",
      time: "रणनीति दायरा",
      btn: "ट्रेड सिग्नल की गणना करें",
      loading: "डेटा प्रोसेस हो रहा है...",
      desc: "पूरी तरह से स्वचालित स्कैन: मोमेंटम + ट्रेंड + BTC बायस।"
    }
  }[language];

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="bg-[#2b3139]/50 p-6 rounded-2xl border border-[#474d57] shadow-inner backdrop-blur-sm">
        <label className="block text-[10px] font-black text-[#f0b90b] uppercase tracking-[0.3em] mb-4">
          {t.select}
        </label>

        <div className="flex flex-col gap-6">
          <div className="relative group">
            <select 
              value={formData.symbol} 
              onChange={(e) => setFormData(p => ({...p, symbol: e.target.value}))}
              className="w-full bg-[#0b0e11] border-2 border-[#474d57] group-hover:border-[#f0b90b]/50 rounded-xl py-5 px-5 text-white font-black text-2xl appearance-none outline-none transition-all cursor-pointer shadow-xl"
            >
              {TOP_CRYPTOS.map(c => <option key={c} value={c}>{c} / USDT</option>)}
            </select>
            <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none">
              <i className="fa-solid fa-microchip text-[#f0b90b] text-xl opacity-50"></i>
            </div>
          </div>

          <div>
             <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">{t.time}</label>
             <div className="grid grid-cols-3 gap-3">
                {TIMEFRAMES.map(tf => (
                  <button
                    key={tf}
                    type="button"
                    onClick={() => setFormData(p => ({...p, timeframe: tf as Timeframe}))}
                    className={`py-3 text-xs font-black rounded-xl border-2 transition-all ${
                      formData.timeframe === tf 
                      ? 'bg-[#f0b90b] text-black border-[#f0b90b] shadow-lg shadow-[#f0b90b]/20 translate-y-[-2px]' 
                      : 'bg-[#0b0e11] text-gray-400 border-[#2b3139] hover:border-[#474d57]'
                    }`}
                  >
                    {tf}
                  </button>
                ))}
             </div>
          </div>
        </div>
      </div>

      <button 
        type="submit" 
        disabled={isLoading}
        className={`w-full py-6 px-8 rounded-2xl font-black text-xl text-black uppercase tracking-widest shadow-2xl transition-all transform active:scale-[0.96] ${
          isLoading 
          ? 'bg-gray-700 cursor-not-allowed opacity-50' 
          : 'bg-gradient-to-r from-[#f0b90b] to-[#ffda6a] hover:shadow-[#f0b90b]/30 hover:brightness-110'
        }`}
      >
        {isLoading ? (
          <span className="flex items-center justify-center gap-4">
            <i className="fa-solid fa-gear animate-spin"></i>
            {t.loading}
          </span>
        ) : (
          <span className="flex items-center justify-center gap-3">
            {t.btn}
            <i className="fa-solid fa-bolt-lightning"></i>
          </span>
        )}
      </button>

      <div className="flex items-center justify-center gap-2 text-[10px] text-gray-600 font-bold uppercase tracking-widest">
        <i className="fa-solid fa-lock text-[8px] text-[#f0b90b]"></i>
        {t.desc}
      </div>
    </form>
  );
};

export default TradingForm;
